mapper.update:
update process_step set update_time = now()

        ,processId=#{processId}


        ,step_order=#{stepOrder}


        ,material_url=#{materialUrl}


        ,auxiliary_equipment=#{auxiliaryEquipment}



        ,auxiliary_materials=#{auxiliaryMaterials}


        ,step_description=#{stepDescription}


        ,remarks=#{remarks}

    where id = #{id}
